    private func findChanges(old: [String: Any], new: [String: Any]) -> [String: (old: Any, new: Any)] {
        var changes: [String: (old: Any, new: Any)] = [:]
        
        for (key, newValue) in new {
            if let oldValue = old[key] {
                if !areEqual(oldValue, newValue) {
                    changes[key] = (old: oldValue, new: newValue)
                }
            } else {
                changes[key] = (old: "N/A", new: newValue)
            }
        }
        
        return changes
    }
    
    private func areEqual(_ lhs: Any, _ rhs: Any) -> Bool {
        if let lhs = lhs as? String, let rhs = rhs as? String {
            return lhs == rhs
        }
        if let lhs = lhs as? Int, let rhs = rhs as? Int {
            return lhs == rhs
        }
        if let lhs = lhs as? Double, let rhs = rhs as? Double {
            return lhs == rhs
        }
        if let lhs = lhs as? Bool, let rhs = rhs as? Bool {
            return lhs == rhs
        }
        return false
    }
