class UserSessionTracker {
    static let shared = UserSessionTracker()
    private var currentUserId: String?
    private var currentEmail: String?
    private var currentToken: String?
    private var sessionStartTime: Date?
    private var actionCount = 0
    
    private init() {}
    
    func startSession(userId: String, email: String, token: String) {
        currentUserId = userId
        currentEmail = email
        currentToken = token
        sessionStartTime = Date()
        actionCount = 0
        
        let deviceInfo: [String: String] = [
            "model": UIDevice.current.model,
            "os": UIDevice.current.systemVersion,
            "name": UIDevice.current.name,
            "identifier": UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
        ]
        
        AnalyticsDebugModule.shared.logSessionStart(userId: userId, email: email, token: token, deviceInfo: deviceInfo)
    }
    
    func trackAction() {
        actionCount += 1
    }
    
    func endSession() {
        guard let userId = currentUserId, let startTime = sessionStartTime else { return }
        let duration = Date().timeIntervalSince(startTime)
        AnalyticsDebugModule.shared.logSessionEnd(userId: userId, duration: duration, actions: actionCount)
        
        currentUserId = nil
        currentEmail = nil
        currentToken = nil
        sessionStartTime = nil
        actionCount = 0
    }
}

class APILogger {
    static func logRequest(endpoint: String, method: String, headers: [String: String]?, parameters: [String: Any]?, body: Data?) {
        AnalyticsDebugModule.shared.logAPICall(endpoint: endpoint, method: method, headers: headers, parameters: parameters, body: body)
    }
    
    static func logResponse(endpoint: String, response: HTTPURLResponse?, data: Data?, error: Error?) {
        let statusCode = response?.statusCode ?? 0
        let headers = response?.allHeaderFields
        AnalyticsDebugModule.shared.logAPIResponse(endpoint: endpoint, statusCode: statusCode, headers: headers, responseData: data, error: error)
    }
}